import React, { useEffect, useState } from 'react';
import axios from 'axios';

const STATUS_LABELS = {
  'Novo': 'Novo',
  'Retorno': 'Retorno',
  'Solicitado': 'Solicitado',
};
const STATUS_COLORS = {
  'Novo': "bg-[#2FA74E] text-white",
  'Retorno': "bg-[#278FFF] text-white",
  'Solicitado': "bg-[#DA3648] text-white",
};

export default function ListaAgendamentos({ onEditar, reloadKey }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  // Filtros e busca
  const [busca, setBusca] = useState('');
  const [filtroData, setFiltroData] = useState('');
  const [filtroHora, setFiltroHora] = useState('');

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/agendamentos')
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, [reloadKey]);

  // Função para filtrar com base na busca e filtros de data/hora
  const filtrarAgendamentos = (lista) => {
    return lista.filter(ag => {
      const textoBusca = busca.toLowerCase();
      const campos = [
        ag.operadorNome,
        ag.auxiliarNome,
        ag.disciplinaNome,
        ag.pacienteNome,
        ag.telefone,
        ag.status
      ].map(x => x ? x.toLowerCase() : '');
      const matchTexto = campos.some(campo => campo.includes(textoBusca));
      const matchData = filtroData ? (ag.data && ag.data.startsWith(filtroData)) : true;
      const matchHora = filtroHora ? (ag.hora && ag.hora.startsWith(filtroHora)) : true;
      return matchTexto && matchData && matchHora;
    });
  };

  const agendamentosFiltrados = filtrarAgendamentos(agendamentos).slice(0, 100);

  // Pega o nome da disciplina e data do primeiro agendamento filtrado para exibir no topo
  const disciplinaNome = agendamentosFiltrados[0]?.disciplinaNome || '';
  const dataAtual = agendamentosFiltrados[0]?.data ? agendamentosFiltrados[0].data.slice(0, 10).split('-').reverse().join('/') : '';
  const semestre = ""; // adapte conforme seu projeto

  // Impressão direta: gera HTML, abre nova janela e imprime
  const handleImprimir = () => {
    const conteudo = `
      <div style="background:#fff;padding:32px;">
        <h2 style="font-size:24px;font-weight:bold;margin-bottom:8px;">Lista de Agendamentos</h2>
        <div style="font-size:18px;">
          <div><b>Disciplina:</b> ${disciplinaNome}</div>
          <div><b>Semestre:</b> ${semestre}</div>
          <div><b>Data:</b> ${dataAtual}</div>
        </div>
        <table border="1" cellspacing="0" cellpadding="8" style="margin-top:24px;width:100%;border-collapse:collapse;font-size:16px;">
          <thead>
            <tr>
              <th style="padding:8px 12px;">N°</th>
              <th style="padding:8px 12px;">Operador</th>
              <th style="padding:8px 12px;">Auxiliar</th>
              <th style="padding:8px 12px;">Paciente</th>
              <th style="padding:8px 12px;">Telefone</th>
              <th style="padding:8px 12px;">Status</th>
            </tr>
          </thead>
          <tbody>
            ${agendamentosFiltrados.map((ag, idx) => `
              <tr>
                <td style="padding:8px 12px;">${idx + 1}</td>
                <td style="padding:8px 12px;">${ag.operadorNome || ''}</td>
                <td style="padding:8px 12px;">${ag.auxiliarNome || ''}</td>
                <td style="padding:8px 12px;">${ag.pacienteNome || ''}</td>
                <td style="padding:8px 12px;">${ag.telefone || ''}</td>
                <td style="padding:8px 12px;">${STATUS_LABELS[ag.status] || ag.status}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
        <style>
          @media print {
            body { background: #fff !important; }
          }
        </style>
      </div>
    `;
    const win = window.open('', '', 'width=900,height=650');
    win.document.write('<html><head><title>Imprimir Lista</title></head><body>');
    win.document.write(conteudo);
    win.document.write('</body></html>');
    win.document.close();
    setTimeout(() => {
      win.print();
      win.close();
    }, 350);
  };

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => {
          setAgendamentos(agendamentos.filter(a => a.id !== id));
        })
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (
   <div className="mt-4">
  <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">Agendamentos</h2>
  {/* Barra de ferramentas */}
  <div className="flex flex-col md:flex-row md:items-end md:justify-between px-2 pb-2 gap-2">
    {/* Campo de busca */}
    <div className="flex-1">
      <input
        type="text"
        className="border rounded-2xl px-4 py-2 w-full"
        placeholder="Pesquisar por Operador, Auxiliar, Disciplina, Paciente, Telefone ou Status"
        value={busca}
        onChange={e => setBusca(e.target.value)}
      />
    </div>
    {/* Ações rápidas */}
    <div className="flex items-center gap-3 mt-2 md:mt-0">
      {/* Filtro Data */}
      <div className="relative group">
        <button
          type="button"
          className="p-2 rounded-full bg-gray-100 hover:bg-gray-200 transition"
          onClick={() => document.getElementById('filtroDataInput').showPicker && document.getElementById('filtroDataInput').showPicker()}
          tabIndex={0}
        >
          {/* Calendar Icon */}
          <svg className="h-6 w-6 text-gray-700" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
            <rect x="3" y="8" width="18" height="13" rx="2" stroke="currentColor" />
            <path d="M16 3v4M8 3v4M3 11h18" stroke="currentColor" />
          </svg>
        </button>
        {/* Tooltip */}
        <span className="absolute z-50 left-1/2 -translate-x-1/2 -top-9 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">
          Filtrar por Data
        </span>
        <input
          type="date"
          id="filtroDataInput"
          className="absolute opacity-0 pointer-events-none"
          style={{width:0, height:0}}
          value={filtroData}
          onChange={e => setFiltroData(e.target.value)}
        />
      </div>
      {/* Filtro Hora */}
      <div className="relative group">
        <button
          type="button"
          className="p-2 rounded-full bg-gray-100 hover:bg-gray-200 transition"
          onClick={() => document.getElementById('filtroHoraInput').showPicker && document.getElementById('filtroHoraInput').showPicker()}
          tabIndex={0}
        >
          {/* Clock Icon */}
          <svg className="h-6 w-6 text-gray-700" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
            <circle cx="12" cy="12" r="10" stroke="currentColor"/>
            <path d="M12 6v6l4 2" stroke="currentColor"/>
          </svg>
        </button>
        {/* Tooltip */}
        <span className="absolute z-50 left-1/2 -translate-x-1/2 -top-9 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">
          Filtrar por Hora
        </span>
        <input
          type="time"
          id="filtroHoraInput"
          className="absolute opacity-0 pointer-events-none"
          style={{width:0, height:0}}
          value={filtroHora}
          onChange={e => setFiltroHora(e.target.value)}
        />
      </div>
      {/* Imprimir */}
      <div className="relative group">
        <button
          className="p-2 rounded-full bg-gray-100 hover:bg-gray-200 transition"
          onClick={handleImprimir}
          type="button"
          tabIndex={0}
        >
          {/* Printer Icon */}
          <svg className="h-6 w-6 text-gray-700" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
            <rect x="6" y="9" width="12" height="7" rx="2" stroke="currentColor"/>
            <path d="M6 17v2a2 2 0 002 2h8a2 2 0 002-2v-2" stroke="currentColor"/>
            <path d="M6 9V5a2 2 0 012-2h8a2 2 0 012 2v4" stroke="currentColor"/>
            <circle cx="18" cy="14" r="1" fill="currentColor"/>
          </svg>
        </button>
        {/* Tooltip */}
        <span className="absolute z-50 left-1/2 -translate-x-1/2 -top-9 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">
          Imprimir Lista
        </span>
      </div>
    </div>
  </div>
  {/* Cabeçalho das colunas */}
  <div className="flex px-5 pb-2 text-gray-500 font-bold text-sm">
    <div className="w-1/12">Nº</div>
    <div className="w-1/6">Operador</div>
    <div className="w-1/6">Auxiliar</div>
    <div className="w-1/6">Disciplina</div>
    <div className="w-1/6">Paciente</div>
    <div className="w-1/12">Data</div>
    <div className="w-1/12">Hora</div>
    <div className="w-1/12">Status</div>
    <div className="w-1/12 text-right">Ações</div>
  </div>
  <ul className="space-y-3">
    {agendamentosFiltrados.map((ag, idx) => (
      <li
        key={ag.id || idx}
        className="flex items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
      >
        <div className="w-1/12 text-gray-700">{idx + 1}</div>
        <div className="w-1/6 text-gray-800 font-medium truncate">{ag.operadorNome}</div>
        <div className="w-1/6 text-gray-700 truncate">{ag.auxiliarNome}</div>
        <div className="w-1/6 text-gray-700 truncate">{ag.disciplinaNome}</div>
        <div className="w-1/6 text-gray-700 truncate">{ag.pacienteNome}</div>
        <div className="w-1/12 text-gray-500">{ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : ''}</div>
        <div className="w-1/12 text-gray-500">{ag.hora}</div>
        <div className="w-1/12">
          <span
            className={
              "inline-block px-3 py-1 rounded-full text-xs font-semibold " +
              (STATUS_COLORS[ag.status] || "bg-gray-200 text-gray-700")
            }
          >
            {STATUS_LABELS[ag.status] || ag.status}
          </span>
        </div>
        <div className="w-1/12 flex justify-end space-x-2">
          <button
            onClick={() => onEditar && onEditar(ag)}
            className="px-3 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
            title="Editar"
            type="button"
          >
            Editar
          </button>
          <button
            onClick={() => handleDeletar(ag.id)}
            className="px-3 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
            title="Deletar"
            type="button"
          >
            Deletar
          </button>
        </div>
      </li>
    ))}
  </ul>
</div>

  );
}
